import{BandsToProps}from"./BandsToProps.js";class Frame extends BandsToProps{constructor(){super(),this.attachShadow({mode:"open"}),this.propsRoot=this.shadowRoot.host}onblamready(){super.onblamready(),this.init()}render(band,interval,ratio){this.shadowRoot.innerHTML=`\n      <style>\n        :host {\n          container-type: size;\n          aspect-ratio: ${ratio};\n          display: flex !important;\n          justify-content: center;\n          align-items: center;\n          gap: 1cqw;\n        }\n\n        :host > * {\n          flex-grow: 1;\n          block-size: 100cqh;\n          transform: scaleY(${band});\n          transition: transform ${interval} linear;\n          background-color: #fff;\n        }\n      </style>\n      ${this.renderItems()}\n    `}init(){let band=`var(--${this.name}-freq)`,interval=`var(--${this.name}-interval)`;this.render(band,interval,this.ratio,this.count)}declaration(i){return`--${this.name}-freq: var(--${this.name}-freq-${i}, 0)`}renderItems(){let indices=this.createIndices(this.count),items=[];for(let i=0;i<this.count;i++)items.push(this.renderItem(indices[i]));return items.join("\n")}renderItem(i){return`\n      <div style="${this.declaration(i)}"></div>\n    `}get count(){let value=this.getAttribute("count");return value?parseFloat(value):16}set count(value){this.setAttribute("count",value)}get ratio(){return this.getAttribute("ratio")||"16 / 9"}set ratio(value){this.setAttribute("ratio",value)}}export{Frame};